create extension if not exists pgcrypto;

create table if not exists public.ingredients (
  id uuid primary key default gen_random_uuid(),
  name text unique not null,
  aliases jsonb default '[]'::jsonb,
  category text,
  common_dose_min numeric,
  common_dose_max numeric,
  unit text,
  default_dose numeric,
  gummy_suitability text,
  taste_risk text,
  heat_sensitivity text,
  oil_soluble boolean default false,
  mineral_heavy boolean default false,
  requires_rd_review boolean default false,
  regulatory_review_required boolean default false,
  notes text,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

alter table public.ingredients
  add column if not exists id uuid default gen_random_uuid(),
  add column if not exists name text,
  add column if not exists aliases jsonb default '[]'::jsonb,
  add column if not exists category text,
  add column if not exists common_dose_min numeric,
  add column if not exists common_dose_max numeric,
  add column if not exists unit text,
  add column if not exists default_dose numeric,
  add column if not exists gummy_suitability text,
  add column if not exists taste_risk text,
  add column if not exists heat_sensitivity text,
  add column if not exists oil_soluble boolean default false,
  add column if not exists mineral_heavy boolean default false,
  add column if not exists requires_rd_review boolean default false,
  add column if not exists regulatory_review_required boolean default false,
  add column if not exists notes text,
  add column if not exists created_at timestamptz default now(),
  add column if not exists updated_at timestamptz default now();

alter table public.ingredients
  alter column id set default gen_random_uuid(),
  alter column name set not null,
  alter column aliases set default '[]'::jsonb,
  alter column oil_soluble set default false,
  alter column mineral_heavy set default false,
  alter column requires_rd_review set default false,
  alter column regulatory_review_required set default false,
  alter column created_at set default now(),
  alter column updated_at set default now();

create unique index if not exists ingredients_name_key
  on public.ingredients (name);

grant select, insert on public.ingredients to anon, authenticated;
grant update (aliases, category, common_dose_min, common_dose_max, unit, default_dose, gummy_suitability, taste_risk, heat_sensitivity, oil_soluble, mineral_heavy, requires_rd_review, regulatory_review_required, notes, updated_at)
  on public.ingredients to anon, authenticated;

grant select, insert on public.ingredient_prices to anon, authenticated;
grant update (price_per_kg_usd, price_confidence, last_updated, notes)
  on public.ingredient_prices to anon, authenticated;

