on conflict (name) do update set
  aliases = excluded.aliases,
  category = excluded.category,
  common_dose_min = excluded.common_dose_min,
  common_dose_max = excluded.common_dose_max,
  unit = excluded.unit,
  default_dose = excluded.default_dose,
  gummy_suitability = excluded.gummy_suitability,
  taste_risk = excluded.taste_risk,
  heat_sensitivity = excluded.heat_sensitivity,
  oil_soluble = excluded.oil_soluble,
  mineral_heavy = excluded.mineral_heavy,
  requires_rd_review = excluded.requires_rd_review,
  regulatory_review_required = excluded.regulatory_review_required,
  notes = excluded.notes,
  updated_at = now();
